/// Fast exp() for audio circuit simulation.
/// Input clamped to [-40, 40] (matches melange safe_exp convention).
///
/// Default: polynomial approximation (<0.0004% error, ~6x faster than libm).
/// To use hardware/libm exp, compile with: `--cfg melange_precise_exp`
#[inline(always)]
fn fast_exp(x: f64) -> f64 {
    #[cfg(melange_precise_exp)]
    {
        x.clamp(-40.0, 40.0).exp()
    }
    #[cfg(not(melange_precise_exp))]
    {
        // Range reduction + 5th-order minimax polynomial. <0.0004% max relative error.
        // No lookup tables, no libm dependency, branchless hot path.
        let x = x.clamp(-40.0, 40.0);
        const LN2_INV: f64 = 1.4426950408889634;
        const LN2_HI: f64 = 0.6931471803691238;
        const LN2_LO: f64 = 1.9082149292705877e-10;
        const SHIFT: f64 = 6755399441055744.0; // 2^52 + 2^51
        let z = x * LN2_INV + SHIFT;
        let n_i64 = z.to_bits() as i64 - SHIFT.to_bits() as i64;
        let n = n_i64 as f64;
        let f = (x - n * LN2_HI) - n * LN2_LO;
        let p = 1.0
            + f * (1.0
                + f * (0.5
                    + f * (0.16666666666666607
                        + f * (0.04166666666665876 + f * 0.008333333333492337))));
        let pow2n = f64::from_bits(((1023 + n_i64) as u64) << 52);
        p * pow2n
    }
}

// Canonical source: melange-primitives/src/nr.rs (pnjlim, fetlim)
// Duplicated here because generated code must be self-contained.

/// SPICE PN junction voltage limiting (from SPICE3f5 DEVpnjlim).
///
/// Limits large forward voltage steps on exponential I-V curves using
/// logarithmic compression. Only activates when vnew > vcrit with large step.
#[inline(always)]
fn pnjlim(vnew: f64, vold: f64, vt: f64, vcrit: f64) -> f64 {
    if vnew > vcrit && (vnew - vold).abs() > vt + vt {
        if vold >= 0.0 {
            let arg = 1.0 + (vnew - vold) / vt;
            if arg > 0.0 {
                vold + vt * arg.ln()
            } else {
                vcrit
            }
        } else {
            vt * (vnew / vt).ln()
        }
    } else {
        vnew
    }
}

/// SPICE FET voltage limiting (from SPICE3f5 DEVfetlim).
///
/// Prevents gate-source voltage from jumping across threshold boundary.
/// The allowed step size adapts to the distance from threshold.
#[inline(always)]
fn fetlim(vnew: f64, vold: f64, vto: f64) -> f64 {
    let delv = vnew - vold;
    let vtox = vto + 3.5;
    let vtsthi = (2.0 * (vold - vto)).abs() + 2.0;
    let vtstlo = vtsthi / 2.0 + 2.0;

    if vold >= vto {
        // Device is "on"
        if vold >= vtox {
            if delv <= 0.0 {
                // Going off
                if vnew >= vtox {
                    if -delv > vtstlo {
                        return vold - vtstlo;
                    }
                } else {
                    return vnew.max(vto + 2.0);
                }
            } else {
                // Staying on
                if delv >= vtsthi {
                    return vold + vtsthi;
                }
            }
        } else {
            // Middle region
            if delv <= 0.0 {
                return vnew.max(vto - 0.5);
            } else {
                return vnew.min(vto + 4.0);
            }
        }
    } else {
        // Device is "off"
        if delv <= 0.0 {
            if -delv > vtstlo {
                return vold - vtstlo;
            }
        } else if vnew <= vto + 0.5 {
            if delv > vtstlo {
                return vold + vtstlo;
            }
        } else {
            return vto + 0.5;
        }
    }
    vnew
}

// Canonical source: melange-devices/src/bjt.rs (BjtEbersMoll, BjtGummelPoon)
// Duplicated here because generated code must be self-contained.

/// Safe exponential using fast_exp (clamp to prevent overflow, matches runtime [-40, 40] range)
#[inline(always)]
fn safe_exp(x: f64) -> f64 {
    fast_exp(x)
}

/// Gummel-Poon base charge factor qb.
///
/// Accounts for Early effect (VAF/VAR) and high-level injection (IKF).
/// When use_gp=false or all GP params are infinite, returns 1.0 (Ebers-Moll).
/// nf: forward emission coefficient (uses NF*VT for forward exponential).
#[inline(always)]
fn bjt_qb(
    vbe: f64,
    vbc: f64,
    is: f64,
    vt: f64,
    nf: f64,
    sign: f64,
    use_gp: bool,
    vaf: f64,
    var: f64,
    ikf: f64,
    ikr: f64,
) -> f64 {
    if !use_gp {
        return 1.0;
    }
    let vbe_eff = sign * vbe;
    let vbc_eff = sign * vbc;

    // Early effect: q1 = 1 / (1 - Vbe/VAR - Vbc/VAF)
    let q1_denom = 1.0 - vbe_eff / var - vbc_eff / vaf;
    if q1_denom.abs() < 1e-30 {
        return 1.0;
    }
    let q1 = 1.0 / q1_denom;

    // High-level injection: q2 = Is*exp(Vbe/(NF*Vt))/IKF + Is*exp(Vbc/Vt)/IKR
    let nf_vt = nf * vt;
    let exp_be = safe_exp(vbe_eff / nf_vt);
    let exp_bc = safe_exp(vbc_eff / vt);
    let q2 = is * exp_be / ikf + is * exp_bc / ikr;

    q1 * (1.0 + (1.0 + 4.0 * q2).max(0.0).sqrt()) / 2.0
}

/// BJT collector current Ic(Vbe, Vbc)
/// sign: +1.0 for NPN, -1.0 for PNP (applied to voltages and output current)
/// nf: forward emission coefficient. Transport current uses exp(Vbe/(NF*VT)).
/// When use_gp=true, divides transport current by qb (Gummel-Poon).
#[inline(always)]
fn bjt_ic(
    vbe: f64,
    vbc: f64,
    is: f64,
    vt: f64,
    nf: f64,
    beta_r: f64,
    sign: f64,
    use_gp: bool,
    vaf: f64,
    var: f64,
    ikf: f64,
    ikr: f64,
) -> f64 {
    let vbe_eff = sign * vbe;
    let vbc_eff = sign * vbc;
    let nf_vt = nf * vt;
    let exp_be = safe_exp(vbe_eff / nf_vt);
    let exp_bc = safe_exp(vbc_eff / vt);
    let i_cc = is * (exp_be - exp_bc);
    let qb = bjt_qb(vbe, vbc, is, vt, nf, sign, use_gp, vaf, var, ikf, ikr);
    sign * (i_cc / qb - is / beta_r * (exp_bc - 1.0))
}

/// BJT base current Ib(Vbe, Vbc)
/// sign: +1.0 for NPN, -1.0 for PNP
/// nf: forward emission coefficient for ideal base current.
/// ise, ne: B-E leakage saturation current and emission coefficient.
/// Base current is NOT modified by Gummel-Poon in standard formulation.
#[inline(always)]
fn bjt_ib(
    vbe: f64,
    vbc: f64,
    is: f64,
    vt: f64,
    nf: f64,
    beta_f: f64,
    beta_r: f64,
    sign: f64,
    ise: f64,
    ne: f64,
) -> f64 {
    let vbe_eff = sign * vbe;
    let vbc_eff = sign * vbc;
    let nf_vt = nf * vt;
    let exp_be = safe_exp(vbe_eff / nf_vt);
    let exp_bc = safe_exp(vbc_eff / vt);
    let mut ib = is / beta_f * (exp_be - 1.0) + is / beta_r * (exp_bc - 1.0);
    // B-E leakage current: ISE * (exp(Vbe/(NE*VT)) - 1)
    if ise > 0.0 {
        let ne_vt = ne * vt;
        let exp_be_leak = safe_exp(vbe_eff / ne_vt);
        ib += ise * (exp_be_leak - 1.0);
    }
    sign * ib
}

/// BJT Jacobian: [dIc/dVbe, dIc/dVbc, dIb/dVbe, dIb/dVbc]
/// sign: +1.0 for NPN, -1.0 for PNP (s*s=1, so Jacobian entries are polarity-invariant)
/// nf: forward emission coefficient. ise, ne: leakage current params.
/// When use_gp=true, uses quotient rule for d(Icc/qb)/dV (Gummel-Poon).
#[inline(always)]
fn bjt_jacobian(
    vbe: f64,
    vbc: f64,
    is: f64,
    vt: f64,
    nf: f64,
    beta_f: f64,
    beta_r: f64,
    sign: f64,
    use_gp: bool,
    vaf: f64,
    var: f64,
    ikf: f64,
    ikr: f64,
    ise: f64,
    ne: f64,
) -> [f64; 4] {
    let vbe_eff = sign * vbe;
    let vbc_eff = sign * vbc;
    let nf_vt = nf * vt;
    let exp_be = safe_exp(vbe_eff / nf_vt);
    let exp_bc = safe_exp(vbc_eff / vt);

    // Base current Jacobian (unchanged by GP)
    let mut dib_dvbe = (is / (beta_f * nf_vt)) * exp_be;
    let dib_dvbc = (is / (beta_r * vt)) * exp_bc;
    // ISE leakage contribution to dIb/dVbe
    if ise > 0.0 {
        let ne_vt = ne * vt;
        let exp_be_leak = safe_exp(vbe_eff / ne_vt);
        dib_dvbe += (ise / ne_vt) * exp_be_leak;
    }

    if !use_gp {
        // Ebers-Moll: simple derivatives
        let dic_dvbe = is / nf_vt * exp_be;
        let dic_dvbc = -(is / vt) * exp_bc - (is / (beta_r * vt)) * exp_bc;
        return [dic_dvbe, dic_dvbc, dib_dvbe, dib_dvbc];
    }

    // Gummel-Poon: quotient rule for d(Icc/qb)/dV
    let icc = is * (exp_be - exp_bc);
    let dicc_dvbe = is / nf_vt * exp_be;
    let dicc_dvbc = -is / vt * exp_bc;

    // q1 and derivatives
    let q1_denom = 1.0 - vbe_eff / var - vbc_eff / vaf;
    let (q1, dq1_dvbe, dq1_dvbc) = if q1_denom.abs() < 1e-30 {
        (1.0, 0.0, 0.0)
    } else {
        let q1 = 1.0 / q1_denom;
        (q1, q1 * q1 / var, q1 * q1 / vaf)
    };

    // q2 and derivatives: q2 = Is*exp(Vbe/(NF*Vt))/IKF + Is*exp(Vbc/Vt)/IKR
    let q2 = is * exp_be / ikf + is * exp_bc / ikr;
    let dq2_dvbe = is / (nf_vt * ikf) * exp_be;
    let dq2_dvbc = is / (vt * ikr) * exp_bc;

    // Discriminant D = sqrt(1 + 4*q2)
    let disc = (1.0 + 4.0 * q2).max(0.0);
    let d = disc.sqrt();
    let dd_dvbe = if d > 1e-15 { 2.0 * dq2_dvbe / d } else { 0.0 };
    let dd_dvbc = if d > 1e-15 { 2.0 * dq2_dvbc / d } else { 0.0 };

    // qb = q1 * (1 + D) / 2
    let qb = q1 * (1.0 + d) / 2.0;
    let dqb_dvbe = dq1_dvbe * (1.0 + d) / 2.0 + q1 * dd_dvbe / 2.0;
    let dqb_dvbc = dq1_dvbc * (1.0 + d) / 2.0 + q1 * dd_dvbc / 2.0;

    // Quotient rule: d(Icc/qb)/dV = (dIcc/dV * qb - Icc * dqb/dV) / qb^2
    let qb2 = (qb * qb).max(1e-30);
    let quotient_dvbe = (dicc_dvbe * qb - icc * dqb_dvbe) / qb2;
    let quotient_dvbc = (dicc_dvbc * qb - icc * dqb_dvbc) / qb2;

    let d_bc_term_dvbc = is / (beta_r * vt) * exp_bc;

    [
        quotient_dvbe,
        quotient_dvbc - d_bc_term_dvbc,
        dib_dvbe,
        dib_dvbc,
    ]
}

/// Combined BJT evaluation: returns (Ic, Ib, [dIc/dVbe, dIc/dVbc, dIb/dVbe, dIb/dVbc]).
///
/// Computes exp(Vbe/(NF*VT)) and exp(Vbc/VT) once and shares them across current
/// and Jacobian calculations. Reduces from 8-10 exp() to 2-3 per evaluation.
#[inline(always)]
fn bjt_evaluate(
    vbe: f64,
    vbc: f64,
    is: f64,
    vt: f64,
    nf: f64,
    beta_f: f64,
    beta_r: f64,
    sign: f64,
    use_gp: bool,
    vaf: f64,
    var: f64,
    ikf: f64,
    ikr: f64,
    ise: f64,
    ne: f64,
) -> (f64, f64, [f64; 4]) {
    let vbe_eff = sign * vbe;
    let vbc_eff = sign * vbc;
    let nf_vt = nf * vt;

    // Shared exponentials (computed once)
    let exp_be = safe_exp(vbe_eff / nf_vt);
    let exp_bc = safe_exp(vbc_eff / vt);

    // ISE leakage exponential (computed once, only when needed)
    let exp_be_leak = if ise > 0.0 {
        safe_exp(vbe_eff / (ne * vt))
    } else {
        0.0
    };

    // === Collector current ===
    let i_cc = is * (exp_be - exp_bc);

    // === Base current (not modified by GP) ===
    let mut ib_raw = is / beta_f * (exp_be - 1.0) + is / beta_r * (exp_bc - 1.0);
    if ise > 0.0 {
        ib_raw += ise * (exp_be_leak - 1.0);
    }

    // === Base current Jacobian ===
    let mut dib_dvbe = (is / (beta_f * nf_vt)) * exp_be;
    let dib_dvbc = (is / (beta_r * vt)) * exp_bc;
    if ise > 0.0 {
        let ne_vt = ne * vt;
        dib_dvbe += (ise / ne_vt) * exp_be_leak;
    }

    if !use_gp {
        // Ebers-Moll
        let ic = sign * (i_cc - is / beta_r * (exp_bc - 1.0));
        let ib = sign * ib_raw;
        let dic_dvbe = is / nf_vt * exp_be;
        let dic_dvbc = -(is / vt) * exp_bc - (is / (beta_r * vt)) * exp_bc;
        return (ic, ib, [dic_dvbe, dic_dvbc, dib_dvbe, dib_dvbc]);
    }

    // Gummel-Poon
    // q1 and derivatives
    let q1_denom = 1.0 - vbe_eff / var - vbc_eff / vaf;
    let (q1, dq1_dvbe, dq1_dvbc) = if q1_denom.abs() < 1e-30 {
        (1.0, 0.0, 0.0)
    } else {
        let q1 = 1.0 / q1_denom;
        (q1, q1 * q1 / var, q1 * q1 / vaf)
    };

    // q2 and derivatives (uses shared exp_be, exp_bc)
    let q2 = is * exp_be / ikf + is * exp_bc / ikr;
    let dq2_dvbe = is / (nf_vt * ikf) * exp_be;
    let dq2_dvbc = is / (vt * ikr) * exp_bc;

    // Discriminant D = sqrt(1 + 4*q2)
    let disc = (1.0 + 4.0 * q2).max(0.0);
    let d = disc.sqrt();
    let dd_dvbe = if d > 1e-15 { 2.0 * dq2_dvbe / d } else { 0.0 };
    let dd_dvbc = if d > 1e-15 { 2.0 * dq2_dvbc / d } else { 0.0 };

    // qb = q1 * (1 + D) / 2
    let qb = q1 * (1.0 + d) / 2.0;
    let dqb_dvbe = dq1_dvbe * (1.0 + d) / 2.0 + q1 * dd_dvbe / 2.0;
    let dqb_dvbc = dq1_dvbc * (1.0 + d) / 2.0 + q1 * dd_dvbc / 2.0;

    let ic = sign * (i_cc / qb - is / beta_r * (exp_bc - 1.0));
    let ib = sign * ib_raw;

    // Quotient rule: d(Icc/qb)/dV = (dIcc/dV * qb - Icc * dqb/dV) / qb^2
    let dicc_dvbe = is / nf_vt * exp_be;
    let dicc_dvbc = -is / vt * exp_bc;
    let qb2 = (qb * qb).max(1e-30);
    let quotient_dvbe = (dicc_dvbe * qb - i_cc * dqb_dvbe) / qb2;
    let quotient_dvbc = (dicc_dvbc * qb - i_cc * dqb_dvbc) / qb2;
    let d_bc_term_dvbc = is / (beta_r * vt) * exp_bc;

    (
        ic,
        ib,
        [
            quotient_dvbe,
            quotient_dvbc - d_bc_term_dvbc,
            dib_dvbe,
            dib_dvbc,
        ],
    )
}

/// BJT with parasitic resistances (RB, RC, RE).
///
/// Given external junction voltages (Vbe_ext, Vbc_ext), solves for internal
/// junction voltages via inner 2D Newton-Raphson, then returns:
///   (Ic, Ib, [dIc/dVbe_ext, dIc/dVbc_ext, dIb/dVbe_ext, dIb/dVbc_ext])
///
/// The inner NR solves: find (Vbe_int, Vbc_int) such that
///   F1 = Vbe_int - Vbe_ext + Ib*RB + (Ic+Ib)*RE = 0
///   F2 = Vbc_int - Vbc_ext + Ib*RB - Ic*RC = 0
/// (note: RE term uses Ie = -(Ic+Ib), so V_E_int = V_E_ext - Ie*RE = V_E_ext + (Ic+Ib)*RE)
///
/// When RB=RC=RE=0, this reduces to direct evaluation (no inner loop).
#[inline(always)]
fn bjt_with_parasitics(
    vbe_ext: f64,
    vbc_ext: f64,
    is: f64,
    vt: f64,
    nf: f64,
    beta_f: f64,
    beta_r: f64,
    sign: f64,
    use_gp: bool,
    vaf: f64,
    var: f64,
    ikf: f64,
    ikr: f64,
    ise: f64,
    ne: f64,
    rb: f64,
    rc: f64,
    re: f64,
) -> (f64, f64, [f64; 4]) {
    const INNER_MAX_ITER: usize = 15;
    const INNER_TOL: f64 = 1e-10;

    // Initial guess: internal = external
    let mut vbe_int = vbe_ext;
    let mut vbc_int = vbc_ext;

    for _iter in 0..INNER_MAX_ITER {
        let (ic, ib, jac_int) = bjt_evaluate(
            vbe_int, vbc_int, is, vt, nf, beta_f, beta_r, sign, use_gp, vaf, var, ikf, ikr, ise, ne,
        );
        let dic_dvbe = jac_int[0];
        let dic_dvbc = jac_int[1];
        let dib_dvbe = jac_int[2];
        let dib_dvbc = jac_int[3];

        // Residuals
        let f1 = vbe_int - vbe_ext + ib * rb + (ic + ib) * re;
        let f2 = vbc_int - vbc_ext + ib * rb - ic * rc;

        if f1.abs() < INNER_TOL && f2.abs() < INNER_TOL {
            break;
        }

        // Jacobian of F w.r.t. (Vbe_int, Vbc_int)
        let j11 = 1.0 + dib_dvbe * rb + (dic_dvbe + dib_dvbe) * re;
        let j12 = dib_dvbc * rb + (dic_dvbc + dib_dvbc) * re;
        let j21 = dib_dvbe * rb - dic_dvbe * rc;
        let j22 = 1.0 + dib_dvbc * rb - dic_dvbc * rc;

        // Solve 2x2 via Cramer's rule
        let det = j11 * j22 - j12 * j21;
        if det.abs() < 1e-30 {
            break;
        }
        let inv_det = 1.0 / det;
        let dvbe = (j22 * f1 - j12 * f2) * inv_det;
        let dvbc = (j11 * f2 - j21 * f1) * inv_det;

        // Step limiting: max ±4*VT per iteration
        let max_step = 4.0 * vt;
        let dvbe = dvbe.clamp(-max_step, max_step);
        let dvbc = dvbc.clamp(-max_step, max_step);

        vbe_int -= dvbe;
        vbc_int -= dvbc;
    }

    // Final evaluation at converged internal voltages
    let (ic, ib, jac_int) = bjt_evaluate(
        vbe_int, vbc_int, is, vt, nf, beta_f, beta_r, sign, use_gp, vaf, var, ikf, ikr, ise, ne,
    );

    // External Jacobian: J_ext = J_device * J_F^{-1}
    // J_F = [[j11, j12], [j21, j22]] (recompute at converged point)
    let dic_dvbe = jac_int[0];
    let dic_dvbc = jac_int[1];
    let dib_dvbe = jac_int[2];
    let dib_dvbc = jac_int[3];

    let j11 = 1.0 + dib_dvbe * rb + (dic_dvbe + dib_dvbe) * re;
    let j12 = dib_dvbc * rb + (dic_dvbc + dib_dvbc) * re;
    let j21 = dib_dvbe * rb - dic_dvbe * rc;
    let j22 = 1.0 + dib_dvbc * rb - dic_dvbc * rc;

    let det = j11 * j22 - j12 * j21;
    if det.abs() < 1e-30 {
        // Fallback: return intrinsic Jacobian
        return (ic, ib, jac_int);
    }
    let inv_det = 1.0 / det;

    // J_F^{-1} = [[j22, -j12], [-j21, j11]] / det
    let fi11 = j22 * inv_det;
    let fi12 = -j12 * inv_det;
    let fi21 = -j21 * inv_det;
    let fi22 = j11 * inv_det;

    // J_ext = J_device * J_F^{-1}
    let dic_dvbe_ext = dic_dvbe * fi11 + dic_dvbc * fi21;
    let dic_dvbc_ext = dic_dvbe * fi12 + dic_dvbc * fi22;
    let dib_dvbe_ext = dib_dvbe * fi11 + dib_dvbc * fi21;
    let dib_dvbc_ext = dib_dvbe * fi12 + dib_dvbc * fi22;

    (
        ic,
        ib,
        [dic_dvbe_ext, dic_dvbc_ext, dib_dvbe_ext, dib_dvbc_ext],
    )
}

/// Build RHS vector: rhs = rhs_const + A_neg * v_prev + N_i^T * i_nl_prev + input
///
/// The A_neg * v_prev term captures capacitor history contribution
/// via alpha*C*v_prev (implicit in the matrix formulation).
#[inline(always)]
fn build_rhs(input: f64, input_prev: f64, state: &CircuitState) -> [f64; N] {
    let mut rhs = RHS_CONST;

    // A_neg * v_prev contribution (includes alpha*C*v_prev capacitor history)
    rhs[0] += state.a_neg[0][0] * state.v_prev[0] + state.a_neg[0][1] * state.v_prev[1];
    rhs[1] += state.a_neg[1][0] * state.v_prev[0]
        + state.a_neg[1][1] * state.v_prev[1]
        + state.a_neg[1][2] * state.v_prev[2]
        + state.a_neg[1][4] * state.v_prev[4];
    rhs[2] += state.a_neg[2][1] * state.v_prev[1]
        + state.a_neg[2][2] * state.v_prev[2]
        + state.a_neg[2][6] * state.v_prev[6];
    rhs[3] += state.a_neg[3][3] * state.v_prev[3] + state.a_neg[3][14] * state.v_prev[14];
    rhs[4] += state.a_neg[4][1] * state.v_prev[1]
        + state.a_neg[4][4] * state.v_prev[4]
        + state.a_neg[4][7] * state.v_prev[7]
        + state.a_neg[4][10] * state.v_prev[10];
    rhs[5] += state.a_neg[5][5] * state.v_prev[5] + state.a_neg[5][6] * state.v_prev[6];
    rhs[6] += state.a_neg[6][2] * state.v_prev[2]
        + state.a_neg[6][5] * state.v_prev[5]
        + state.a_neg[6][6] * state.v_prev[6];
    rhs[7] += state.a_neg[7][4] * state.v_prev[4]
        + state.a_neg[7][7] * state.v_prev[7]
        + state.a_neg[7][16] * state.v_prev[16];
    rhs[8] += state.a_neg[8][8] * state.v_prev[8] + state.a_neg[8][11] * state.v_prev[11];
    rhs[9] += state.a_neg[9][9] * state.v_prev[9];
    rhs[10] += state.a_neg[10][4] * state.v_prev[4]
        + state.a_neg[10][10] * state.v_prev[10]
        + state.a_neg[10][16] * state.v_prev[16]
        + state.a_neg[10][17] * state.v_prev[17];
    rhs[11] += state.a_neg[11][8] * state.v_prev[8] + state.a_neg[11][11] * state.v_prev[11];
    rhs[12] += state.a_neg[12][12] * state.v_prev[12]
        + state.a_neg[12][14] * state.v_prev[14]
        + state.a_neg[12][15] * state.v_prev[15];
    rhs[14] += state.a_neg[14][3] * state.v_prev[3]
        + state.a_neg[14][12] * state.v_prev[12]
        + state.a_neg[14][14] * state.v_prev[14]
        + state.a_neg[14][15] * state.v_prev[15];
    rhs[15] += state.a_neg[15][12] * state.v_prev[12]
        + state.a_neg[15][14] * state.v_prev[14]
        + state.a_neg[15][15] * state.v_prev[15];
    rhs[16] += state.a_neg[16][7] * state.v_prev[7]
        + state.a_neg[16][10] * state.v_prev[10]
        + state.a_neg[16][16] * state.v_prev[16]
        + state.a_neg[16][17] * state.v_prev[17];
    rhs[17] += state.a_neg[17][10] * state.v_prev[10]
        + state.a_neg[17][16] * state.v_prev[16]
        + state.a_neg[17][17] * state.v_prev[17];

    // Add N_i * i_nl_prev contribution
    rhs[1] += N_I[0][1] * state.i_nl_prev[0];
    rhs[2] += N_I[0][2] * state.i_nl_prev[0];
    rhs[2] += N_I[1][2] * state.i_nl_prev[1];
    rhs[3] += N_I[4][3] * state.i_nl_prev[4];
    rhs[4] += N_I[0][4] * state.i_nl_prev[0];
    rhs[4] += N_I[2][4] * state.i_nl_prev[2];
    rhs[5] += N_I[1][5] * state.i_nl_prev[1];
    rhs[6] += N_I[1][6] * state.i_nl_prev[1];
    rhs[7] += N_I[2][7] * state.i_nl_prev[2];
    rhs[7] += N_I[6][7] * state.i_nl_prev[6];
    rhs[10] += N_I[2][10] * state.i_nl_prev[2];
    rhs[10] += N_I[5][10] * state.i_nl_prev[5];
    rhs[12] += N_I[3][12] * state.i_nl_prev[3];
    rhs[14] += N_I[3][14] * state.i_nl_prev[3];
    rhs[14] += N_I[4][14] * state.i_nl_prev[4];
    rhs[15] += N_I[3][15] * state.i_nl_prev[3];
    rhs[15] += N_I[4][15] * state.i_nl_prev[4];
    rhs[16] += N_I[5][16] * state.i_nl_prev[5];
    rhs[16] += N_I[6][16] * state.i_nl_prev[6];
    rhs[17] += N_I[5][17] * state.i_nl_prev[5];
    rhs[17] += N_I[6][17] * state.i_nl_prev[6];

    // Add input contribution (Thevenin: (V_in + V_in_prev) * G_in)
    rhs[INPUT_NODE] += (input + input_prev) / INPUT_RESISTANCE;

    rhs
}

/// Multiply vector by S matrix: result = state.s * rhs
#[inline(always)]
fn mat_vec_mul_s(rhs: &[f64; N], state: &CircuitState) -> [f64; N] {
    let mut result = [0.0f64; N];
    for i in 0..N {
        let mut sum = 0.0;
        for j in 0..N {
            sum += state.s[i][j] * rhs[j];
        }
        result[i] = sum;
    }
    result
}

/// Extract controlling voltages: p = N_v * v_pred
#[inline(always)]
fn extract_controlling_voltages(v_pred: &[f64; N]) -> [f64; M] {
    [
        v_pred[1] - v_pred[2],
        -v_pred[2] + v_pred[6],
        v_pred[4] - v_pred[7],
        v_pred[12] - v_pred[15],
        -v_pred[3] + v_pred[14],
        v_pred[10] - v_pred[17],
        -v_pred[7] + v_pred[16],
    ]
}

/// Solve M×M nonlinear system via Newton-Raphson
///
/// Solves: i_nl - i_d(p + K*i_nl) = 0
/// where p = N_v * v_pred is the linear prediction
#[inline(always)]
fn solve_nonlinear(p: &[f64; M], state: &mut CircuitState) -> [f64; M] {
    const MAX_ITER: usize = 200;
    const TOL: f64 = 1.00000000000000006e-9;
    const SINGULARITY_THRESHOLD: f64 = 1e-15;

    // First-order predictor for NR warm start: i_guess = 2*i_nl[n-1] - i_nl[n-2]
    // Extrapolates the trend from the last two samples. On smooth signals this
    // puts the initial guess much closer to the solution, reducing NR iterations.
    let mut i_nl = [0.0; M];
    for i in 0..M {
        i_nl[i] = 2.0 * state.i_nl_prev[i] - state.i_nl_prev_prev[i];
    }

    // Newton-Raphson iteration
    for iter in 0..MAX_ITER {
        // Compute controlling voltages: v_d = p + K * i_nl
        let v_d0 = p[0]
            + state.k[0][0] * i_nl[0]
            + state.k[0][1] * i_nl[1]
            + state.k[0][2] * i_nl[2]
            + state.k[0][3] * i_nl[3]
            + state.k[0][4] * i_nl[4]
            + state.k[0][5] * i_nl[5]
            + state.k[0][6] * i_nl[6];
        let v_d1 = p[1]
            + state.k[1][0] * i_nl[0]
            + state.k[1][1] * i_nl[1]
            + state.k[1][2] * i_nl[2]
            + state.k[1][3] * i_nl[3]
            + state.k[1][4] * i_nl[4]
            + state.k[1][5] * i_nl[5]
            + state.k[1][6] * i_nl[6];
        let v_d2 = p[2]
            + state.k[2][0] * i_nl[0]
            + state.k[2][1] * i_nl[1]
            + state.k[2][2] * i_nl[2]
            + state.k[2][3] * i_nl[3]
            + state.k[2][4] * i_nl[4]
            + state.k[2][5] * i_nl[5]
            + state.k[2][6] * i_nl[6];
        let v_d3 = p[3]
            + state.k[3][0] * i_nl[0]
            + state.k[3][1] * i_nl[1]
            + state.k[3][2] * i_nl[2]
            + state.k[3][3] * i_nl[3]
            + state.k[3][4] * i_nl[4]
            + state.k[3][5] * i_nl[5]
            + state.k[3][6] * i_nl[6];
        let v_d4 = p[4]
            + state.k[4][0] * i_nl[0]
            + state.k[4][1] * i_nl[1]
            + state.k[4][2] * i_nl[2]
            + state.k[4][3] * i_nl[3]
            + state.k[4][4] * i_nl[4]
            + state.k[4][5] * i_nl[5]
            + state.k[4][6] * i_nl[6];
        let v_d5 = p[5]
            + state.k[5][0] * i_nl[0]
            + state.k[5][1] * i_nl[1]
            + state.k[5][2] * i_nl[2]
            + state.k[5][3] * i_nl[3]
            + state.k[5][4] * i_nl[4]
            + state.k[5][5] * i_nl[5]
            + state.k[5][6] * i_nl[6];
        let v_d6 = p[6]
            + state.k[6][0] * i_nl[0]
            + state.k[6][1] * i_nl[1]
            + state.k[6][2] * i_nl[2]
            + state.k[6][3] * i_nl[3]
            + state.k[6][4] * i_nl[4]
            + state.k[6][5] * i_nl[5]
            + state.k[6][6] * i_nl[6];

        // Evaluate device currents and Jacobians
        // BJT 0 forward-active (1D: Vbe→Ic only)
        let vbe_0 = v_d0 * DEVICE_0_SIGN;
        let exp_be_0 = fast_exp(vbe_0 / (DEVICE_0_NF * state.device_0_vt));
        let i_dev0 = state.device_0_is * (exp_be_0 - 1.0) * DEVICE_0_SIGN;
        let jdev_0_0 = state.device_0_is / (DEVICE_0_NF * state.device_0_vt) * exp_be_0;
        // BJT 1 forward-active (1D: Vbe→Ic only)
        let vbe_1 = v_d1 * DEVICE_1_SIGN;
        let exp_be_1 = fast_exp(vbe_1 / (DEVICE_1_NF * state.device_1_vt));
        let i_dev1 = state.device_1_is * (exp_be_1 - 1.0) * DEVICE_1_SIGN;
        let jdev_1_1 = state.device_1_is / (DEVICE_1_NF * state.device_1_vt) * exp_be_1;
        // BJT 2 forward-active (1D: Vbe→Ic only)
        let vbe_2 = v_d2 * DEVICE_2_SIGN;
        let exp_be_2 = fast_exp(vbe_2 / (DEVICE_2_NF * state.device_2_vt));
        let i_dev2 = state.device_2_is * (exp_be_2 - 1.0) * DEVICE_2_SIGN;
        let jdev_2_2 = state.device_2_is / (DEVICE_2_NF * state.device_2_vt) * exp_be_2;
        // BJT 3 forward-active (1D: Vbe→Ic only)
        let vbe_3 = v_d3 * DEVICE_3_SIGN;
        let exp_be_3 = fast_exp(vbe_3 / (DEVICE_3_NF * state.device_3_vt));
        let i_dev3 = state.device_3_is * (exp_be_3 - 1.0) * DEVICE_3_SIGN;
        let jdev_3_3 = state.device_3_is / (DEVICE_3_NF * state.device_3_vt) * exp_be_3;
        // BJT 4 forward-active (1D: Vbe→Ic only)
        let vbe_4 = v_d4 * DEVICE_4_SIGN;
        let exp_be_4 = fast_exp(vbe_4 / (DEVICE_4_NF * state.device_4_vt));
        let i_dev4 = state.device_4_is * (exp_be_4 - 1.0) * DEVICE_4_SIGN;
        let jdev_4_4 = state.device_4_is / (DEVICE_4_NF * state.device_4_vt) * exp_be_4;
        // BJT 5 forward-active (1D: Vbe→Ic only)
        let vbe_5 = v_d5 * DEVICE_5_SIGN;
        let exp_be_5 = fast_exp(vbe_5 / (DEVICE_5_NF * state.device_5_vt));
        let i_dev5 = state.device_5_is * (exp_be_5 - 1.0) * DEVICE_5_SIGN;
        let jdev_5_5 = state.device_5_is / (DEVICE_5_NF * state.device_5_vt) * exp_be_5;
        // BJT 6 forward-active (1D: Vbe→Ic only)
        let vbe_6 = v_d6 * DEVICE_6_SIGN;
        let exp_be_6 = fast_exp(vbe_6 / (DEVICE_6_NF * state.device_6_vt));
        let i_dev6 = state.device_6_is * (exp_be_6 - 1.0) * DEVICE_6_SIGN;
        let jdev_6_6 = state.device_6_is / (DEVICE_6_NF * state.device_6_vt) * exp_be_6;

        // Residuals: f(i) = i - i_dev(v(i)) = 0
        let f0 = i_nl[0] - i_dev0;
        let f1 = i_nl[1] - i_dev1;
        let f2 = i_nl[2] - i_dev2;
        let f3 = i_nl[3] - i_dev3;
        let f4 = i_nl[4] - i_dev4;
        let f5 = i_nl[5] - i_dev5;
        let f6 = i_nl[6] - i_dev6;

        // Jacobian: J[i][j] = delta_ij - sum_k(jdev_ik * K[k][j])
        let j00 = 1.0 - jdev_0_0 * state.k[0][0];
        let j01 = 0.0 - jdev_0_0 * state.k[0][1];
        let j02 = 0.0 - jdev_0_0 * state.k[0][2];
        let j03 = 0.0 - jdev_0_0 * state.k[0][3];
        let j04 = 0.0 - jdev_0_0 * state.k[0][4];
        let j05 = 0.0 - jdev_0_0 * state.k[0][5];
        let j06 = 0.0 - jdev_0_0 * state.k[0][6];
        let j10 = 0.0 - jdev_1_1 * state.k[1][0];
        let j11 = 1.0 - jdev_1_1 * state.k[1][1];
        let j12 = 0.0 - jdev_1_1 * state.k[1][2];
        let j13 = 0.0 - jdev_1_1 * state.k[1][3];
        let j14 = 0.0 - jdev_1_1 * state.k[1][4];
        let j15 = 0.0 - jdev_1_1 * state.k[1][5];
        let j16 = 0.0 - jdev_1_1 * state.k[1][6];
        let j20 = 0.0 - jdev_2_2 * state.k[2][0];
        let j21 = 0.0 - jdev_2_2 * state.k[2][1];
        let j22 = 1.0 - jdev_2_2 * state.k[2][2];
        let j23 = 0.0 - jdev_2_2 * state.k[2][3];
        let j24 = 0.0 - jdev_2_2 * state.k[2][4];
        let j25 = 0.0 - jdev_2_2 * state.k[2][5];
        let j26 = 0.0 - jdev_2_2 * state.k[2][6];
        let j30 = 0.0 - jdev_3_3 * state.k[3][0];
        let j31 = 0.0 - jdev_3_3 * state.k[3][1];
        let j32 = 0.0 - jdev_3_3 * state.k[3][2];
        let j33 = 1.0 - jdev_3_3 * state.k[3][3];
        let j34 = 0.0 - jdev_3_3 * state.k[3][4];
        let j35 = 0.0 - jdev_3_3 * state.k[3][5];
        let j36 = 0.0 - jdev_3_3 * state.k[3][6];
        let j40 = 0.0 - jdev_4_4 * state.k[4][0];
        let j41 = 0.0 - jdev_4_4 * state.k[4][1];
        let j42 = 0.0 - jdev_4_4 * state.k[4][2];
        let j43 = 0.0 - jdev_4_4 * state.k[4][3];
        let j44 = 1.0 - jdev_4_4 * state.k[4][4];
        let j45 = 0.0 - jdev_4_4 * state.k[4][5];
        let j46 = 0.0 - jdev_4_4 * state.k[4][6];
        let j50 = 0.0 - jdev_5_5 * state.k[5][0];
        let j51 = 0.0 - jdev_5_5 * state.k[5][1];
        let j52 = 0.0 - jdev_5_5 * state.k[5][2];
        let j53 = 0.0 - jdev_5_5 * state.k[5][3];
        let j54 = 0.0 - jdev_5_5 * state.k[5][4];
        let j55 = 1.0 - jdev_5_5 * state.k[5][5];
        let j56 = 0.0 - jdev_5_5 * state.k[5][6];
        let j60 = 0.0 - jdev_6_6 * state.k[6][0];
        let j61 = 0.0 - jdev_6_6 * state.k[6][1];
        let j62 = 0.0 - jdev_6_6 * state.k[6][2];
        let j63 = 0.0 - jdev_6_6 * state.k[6][3];
        let j64 = 0.0 - jdev_6_6 * state.k[6][4];
        let j65 = 0.0 - jdev_6_6 * state.k[6][5];
        let j66 = 1.0 - jdev_6_6 * state.k[6][6];

        // Solve 7x7 system via inline Gaussian elimination
        let mut a = [
            [j00, j01, j02, j03, j04, j05, j06],
            [j10, j11, j12, j13, j14, j15, j16],
            [j20, j21, j22, j23, j24, j25, j26],
            [j30, j31, j32, j33, j34, j35, j36],
            [j40, j41, j42, j43, j44, j45, j46],
            [j50, j51, j52, j53, j54, j55, j56],
            [j60, j61, j62, j63, j64, j65, j66],
        ];
        let mut b = [f0, f1, f2, f3, f4, f5, f6];
        let mut singular = false;
        // Forward elimination with partial pivoting
        for col in 0..7 {
            let mut max_row = col;
            let mut max_val = a[col][col].abs();
            for row in (col + 1)..7 {
                if a[row][col].abs() > max_val {
                    max_val = a[row][col].abs();
                    max_row = row;
                }
            }
            if max_val < SINGULARITY_THRESHOLD {
                singular = true;
                break;
            }
            if max_row != col {
                a.swap(col, max_row);
                b.swap(col, max_row);
            }
            let pivot = a[col][col];
            for row in (col + 1)..7 {
                let factor = a[row][col] / pivot;
                for j in (col + 1)..7 {
                    a[row][j] -= factor * a[col][j];
                }
                b[row] -= factor * b[col];
            }
        }
        if !singular {
            // Back substitution
            for i in (0..7).rev() {
                let mut sum = b[i];
                for j in (i + 1)..7 {
                    sum -= a[i][j] * b[j];
                }
                if a[i][i].abs() < SINGULARITY_THRESHOLD {
                    singular = true;
                    break;
                }
                b[i] = sum / a[i][i];
            }
        }
        if !singular {
            let delta0 = b[0];
            let delta1 = b[1];
            let delta2 = b[2];
            let delta3 = b[3];
            let delta4 = b[4];
            let delta5 = b[5];
            let delta6 = b[6];
            // Voltage-space limiting (SPICE pnjlim/fetlim through K matrix)
            let dv0 = -(state.k[0][0] * delta0
                + state.k[0][1] * delta1
                + state.k[0][2] * delta2
                + state.k[0][3] * delta3
                + state.k[0][4] * delta4
                + state.k[0][5] * delta5
                + state.k[0][6] * delta6);
            let dv1 = -(state.k[1][0] * delta0
                + state.k[1][1] * delta1
                + state.k[1][2] * delta2
                + state.k[1][3] * delta3
                + state.k[1][4] * delta4
                + state.k[1][5] * delta5
                + state.k[1][6] * delta6);
            let dv2 = -(state.k[2][0] * delta0
                + state.k[2][1] * delta1
                + state.k[2][2] * delta2
                + state.k[2][3] * delta3
                + state.k[2][4] * delta4
                + state.k[2][5] * delta5
                + state.k[2][6] * delta6);
            let dv3 = -(state.k[3][0] * delta0
                + state.k[3][1] * delta1
                + state.k[3][2] * delta2
                + state.k[3][3] * delta3
                + state.k[3][4] * delta4
                + state.k[3][5] * delta5
                + state.k[3][6] * delta6);
            let dv4 = -(state.k[4][0] * delta0
                + state.k[4][1] * delta1
                + state.k[4][2] * delta2
                + state.k[4][3] * delta3
                + state.k[4][4] * delta4
                + state.k[4][5] * delta5
                + state.k[4][6] * delta6);
            let dv5 = -(state.k[5][0] * delta0
                + state.k[5][1] * delta1
                + state.k[5][2] * delta2
                + state.k[5][3] * delta3
                + state.k[5][4] * delta4
                + state.k[5][5] * delta5
                + state.k[5][6] * delta6);
            let dv6 = -(state.k[6][0] * delta0
                + state.k[6][1] * delta1
                + state.k[6][2] * delta2
                + state.k[6][3] * delta3
                + state.k[6][4] * delta4
                + state.k[6][5] * delta5
                + state.k[6][6] * delta6);
            let mut alpha = [1.0_f64; 7];
            let mut any_limited = false;
            if dv0.abs() > 1e-15 {
                let v_lim = pnjlim(v_d0 + dv0, v_d0, state.device_0_vt, DEVICE_0_VCRIT);
                let ratio = ((v_lim - v_d0) / dv0).max(0.01);
                if ratio < alpha[0] {
                    alpha[0] = ratio;
                    if ratio < 1.0 {
                        any_limited = true;
                    }
                }
            }
            if dv1.abs() > 1e-15 {
                let v_lim = pnjlim(v_d1 + dv1, v_d1, state.device_1_vt, DEVICE_1_VCRIT);
                let ratio = ((v_lim - v_d1) / dv1).max(0.01);
                if ratio < alpha[1] {
                    alpha[1] = ratio;
                    if ratio < 1.0 {
                        any_limited = true;
                    }
                }
            }
            if dv2.abs() > 1e-15 {
                let v_lim = pnjlim(v_d2 + dv2, v_d2, state.device_2_vt, DEVICE_2_VCRIT);
                let ratio = ((v_lim - v_d2) / dv2).max(0.01);
                if ratio < alpha[2] {
                    alpha[2] = ratio;
                    if ratio < 1.0 {
                        any_limited = true;
                    }
                }
            }
            if dv3.abs() > 1e-15 {
                let v_lim = pnjlim(v_d3 + dv3, v_d3, state.device_3_vt, DEVICE_3_VCRIT);
                let ratio = ((v_lim - v_d3) / dv3).max(0.01);
                if ratio < alpha[3] {
                    alpha[3] = ratio;
                    if ratio < 1.0 {
                        any_limited = true;
                    }
                }
            }
            if dv4.abs() > 1e-15 {
                let v_lim = pnjlim(v_d4 + dv4, v_d4, state.device_4_vt, DEVICE_4_VCRIT);
                let ratio = ((v_lim - v_d4) / dv4).max(0.01);
                if ratio < alpha[4] {
                    alpha[4] = ratio;
                    if ratio < 1.0 {
                        any_limited = true;
                    }
                }
            }
            if dv5.abs() > 1e-15 {
                let v_lim = pnjlim(v_d5 + dv5, v_d5, state.device_5_vt, DEVICE_5_VCRIT);
                let ratio = ((v_lim - v_d5) / dv5).max(0.01);
                if ratio < alpha[5] {
                    alpha[5] = ratio;
                    if ratio < 1.0 {
                        any_limited = true;
                    }
                }
            }
            if dv6.abs() > 1e-15 {
                let v_lim = pnjlim(v_d6 + dv6, v_d6, state.device_6_vt, DEVICE_6_VCRIT);
                let ratio = ((v_lim - v_d6) / dv6).max(0.01);
                if ratio < alpha[6] {
                    alpha[6] = ratio;
                    if ratio < 1.0 {
                        any_limited = true;
                    }
                }
            }
            // Global voltage backstop: limit max voltage change to 3.5V
            let max_dv = (dv0 * alpha[0])
                .abs()
                .max((dv1 * alpha[1]).abs())
                .max((dv2 * alpha[2]).abs())
                .max((dv3 * alpha[3]).abs())
                .max((dv4 * alpha[4]).abs())
                .max((dv5 * alpha[5]).abs())
                .max((dv6 * alpha[6]).abs());
            if max_dv > 3.5 {
                let factor = (3.5 / max_dv).max(0.1);
                for a in alpha.iter_mut() {
                    *a *= factor;
                }
            }
            i_nl[0] -= alpha[0] * delta0;
            i_nl[1] -= alpha[1] * delta1;
            i_nl[2] -= alpha[2] * delta2;
            i_nl[3] -= alpha[3] * delta3;
            i_nl[4] -= alpha[4] * delta4;
            i_nl[5] -= alpha[5] * delta5;
            i_nl[6] -= alpha[6] * delta6;

            // Convergence check (SPICE RELTOL=0.001, VNTOL=1e-6)
            if !any_limited {
                let mut nr_converged = true;
                {
                    let step = alpha[0] * delta0;
                    let v_new = v_d0 + dv0 * alpha[0];
                    let threshold = 1e-3 * v_d0.abs().max(v_new.abs()) + 1e-6;
                    if step.abs() > threshold {
                        nr_converged = false;
                    }
                }
                {
                    let step = alpha[1] * delta1;
                    let v_new = v_d1 + dv1 * alpha[1];
                    let threshold = 1e-3 * v_d1.abs().max(v_new.abs()) + 1e-6;
                    if step.abs() > threshold {
                        nr_converged = false;
                    }
                }
                {
                    let step = alpha[2] * delta2;
                    let v_new = v_d2 + dv2 * alpha[2];
                    let threshold = 1e-3 * v_d2.abs().max(v_new.abs()) + 1e-6;
                    if step.abs() > threshold {
                        nr_converged = false;
                    }
                }
                {
                    let step = alpha[3] * delta3;
                    let v_new = v_d3 + dv3 * alpha[3];
                    let threshold = 1e-3 * v_d3.abs().max(v_new.abs()) + 1e-6;
                    if step.abs() > threshold {
                        nr_converged = false;
                    }
                }
                {
                    let step = alpha[4] * delta4;
                    let v_new = v_d4 + dv4 * alpha[4];
                    let threshold = 1e-3 * v_d4.abs().max(v_new.abs()) + 1e-6;
                    if step.abs() > threshold {
                        nr_converged = false;
                    }
                }
                {
                    let step = alpha[5] * delta5;
                    let v_new = v_d5 + dv5 * alpha[5];
                    let threshold = 1e-3 * v_d5.abs().max(v_new.abs()) + 1e-6;
                    if step.abs() > threshold {
                        nr_converged = false;
                    }
                }
                {
                    let step = alpha[6] * delta6;
                    let v_new = v_d6 + dv6 * alpha[6];
                    let threshold = 1e-3 * v_d6.abs().max(v_new.abs()) + 1e-6;
                    if step.abs() > threshold {
                        nr_converged = false;
                    }
                }
                if nr_converged {
                    state.last_nr_iterations = iter as u32;
                    return i_nl;
                }
            }
        } else {
            // Singular Jacobian — damped fallback (0.5 * residual)
            i_nl[0] -= (f0 * 0.5).clamp(-0.01, 0.01);
            i_nl[1] -= (f1 * 0.5).clamp(-0.01, 0.01);
            i_nl[2] -= (f2 * 0.5).clamp(-0.01, 0.01);
            i_nl[3] -= (f3 * 0.5).clamp(-0.01, 0.01);
            i_nl[4] -= (f4 * 0.5).clamp(-0.01, 0.01);
            i_nl[5] -= (f5 * 0.5).clamp(-0.01, 0.01);
            i_nl[6] -= (f6 * 0.5).clamp(-0.01, 0.01);
        }
    }

    // Max iterations reached - return best guess
    state.last_nr_iterations = MAX_ITER as u32;
    // Safety: check for NaN/Inf and clamp
    if !i_nl[0].is_finite() {
        i_nl[0] = 0.0;
    }
    if !i_nl[1].is_finite() {
        i_nl[1] = 0.0;
    }
    if !i_nl[2].is_finite() {
        i_nl[2] = 0.0;
    }
    if !i_nl[3].is_finite() {
        i_nl[3] = 0.0;
    }
    if !i_nl[4].is_finite() {
        i_nl[4] = 0.0;
    }
    if !i_nl[5].is_finite() {
        i_nl[5] = 0.0;
    }
    if !i_nl[6].is_finite() {
        i_nl[6] = 0.0;
    }

    i_nl
}

/// Compute final node voltages: v = v_pred + state.s_ni * i_nl
///
/// Uses full i_nl (not delta) for trapezoidal nonlinear integration.
/// Combined with N_i * i_nl_prev in the RHS, this gives the proper
/// trapezoidal average: S * N_i * (i_nl + i_nl_prev).
///
/// The S*N_i product is stored in state.s_ni for sample rate independence.
#[inline(always)]
fn compute_final_voltages(v_pred: &[f64; N], i_nl: &[f64; M], state: &CircuitState) -> [f64; N] {
    let mut v = *v_pred;
    for i in 0..N {
        for j in 0..M {
            v[i] += state.s_ni[i][j] * i_nl[j];
        }
    }
    v
}

/// Update capacitor history for companion model.
///
/// NOTE: In the DK method, capacitor history is implicitly handled by
/// the A_neg * v_prev term in build_rhs. This function is a no-op.
#[inline(always)]
fn update_history(_v: &[f64; N], _state: &mut CircuitState) {
    // Capacitor history is handled implicitly by A_neg * v_prev
}

// =============================================================================
// MAIN PROCESS FUNCTION
// =============================================================================

/// Process a single audio sample through the circuit
///
/// # Arguments
/// * `input` - Input voltage at INPUT_NODE
/// * `state` - Mutable circuit state (preserved across calls)
///
/// # Returns
/// Output voltages at OUTPUT_NODES (one per output channel)
#[inline]
pub fn process_sample(input: f64, state: &mut CircuitState) -> [f64; NUM_OUTPUTS] {
    // Validate input — handle NaN, inf, and extreme values
    let input = if input.is_finite() {
        input.clamp(-100.0, 100.0)
    } else {
        0.0
    };

    // Step 1: Build RHS vector from history and input
    let rhs = build_rhs(input, state.input_prev, state);

    // Step 2: Linear prediction: v_pred = S * rhs
    let v_pred = mat_vec_mul_s(&rhs, state);

    // Step 3: Extract controlling voltages for nonlinear devices
    let p = extract_controlling_voltages(&v_pred);

    // Step 4: Solve M×M nonlinear system via Newton-Raphson
    let i_nl = solve_nonlinear(&p, state);

    // Step 5: Compute final node voltages
    let v = compute_final_voltages(&v_pred, &i_nl, state);

    // Step 6: Update history (no-op, handled by A_neg formulation)
    update_history(&v, state);

    // Step 6c: Global node voltage damping safety net.
    // Even after BE fallback, clamp any excessive node voltage changes.
    // Keeps i_nl_prev consistent with v_prev for next sample's RHS.
    let (v, i_nl) = {
        let mut max_delta = 0.0_f64;
        for i in 0..18 {
            let d = (v[i] - state.v_prev[i]).abs();
            if d > max_delta {
                max_delta = d;
            }
        }
        if max_delta > 2.0 {
            let damp = (2.0 / max_delta).max(0.01);
            let mut v_d = v;
            for i in 0..N {
                v_d[i] = state.v_prev[i] + damp * (v[i] - state.v_prev[i]);
            }
            let mut i_d = i_nl;
            for i in 0..M {
                i_d[i] = state.i_nl_prev[i] + damp * (i_nl[i] - state.i_nl_prev[i]);
            }
            (v_d, i_d)
        } else {
            (v, i_nl)
        }
    };

    // Step 7: Update state for next iteration
    state.v_prev = v;
    state.i_nl_prev_prev = state.i_nl_prev;
    state.i_nl_prev = i_nl;
    state.input_prev = input;

    // Step 8: Sanitize state — if NaN/inf entered, reset to DC operating point
    if !state.v_prev.iter().all(|x| x.is_finite()) {
        state.v_prev = state.dc_operating_point;
        state.i_nl_prev = [0.0; M];
        state.i_nl_prev_prev = [0.0; M];
        state.input_prev = 0.0;
        state.diag_nan_reset_count += 1;
        return [0.0; NUM_OUTPUTS];
    }

    if state.last_nr_iterations >= 200 as u32 {
        state.diag_nr_max_iter_count += 1;
    }

    // Step 9: Extract outputs, apply per-output DC blocking filter and scale
    let mut output = [0.0f64; NUM_OUTPUTS];
    for out_idx in 0..NUM_OUTPUTS {
        let raw_out = v[OUTPUT_NODES[out_idx]];
        let raw_out = if raw_out.is_finite() { raw_out } else { 0.0 };
        let dc_blocked = raw_out - state.dc_block_x_prev[out_idx]
            + state.dc_block_r * state.dc_block_y_prev[out_idx];
        state.dc_block_x_prev[out_idx] = raw_out;
        state.dc_block_y_prev[out_idx] = dc_blocked;
        let scaled = dc_blocked * OUTPUT_SCALES[out_idx];
        let abs_out = scaled.abs();
        if abs_out > state.diag_peak_output {
            state.diag_peak_output = abs_out;
        }
        if abs_out > 10.0 {
            state.diag_clamp_count += 1;
        }
        output[out_idx] = scaled.clamp(-10.0, 10.0);
    }
    output
}
